const input = $input.first().json;

// Hae text output nodesta
const text = input.output[0].content[0].text;

// Split rivit ja puhdista
const lines = text
  .split('\n')
  .map(line => line.trim())
  .filter(line => line.length > 0);

// Parse queryt (poista numerot ja välimerkit alusta)
const queries = lines.map(line => {
  // Poista "1. ", "2. ", "3. " ja muut numerot
  return line.replace(/^\d+\.\s*/, '').trim();
});

// Tallenna alkuperäinen kysymys
const originalQuestion = $("Telegram Trigger").first().json.message?.text || "unknown";

// Lisää alkuperäinen kysymys queryihin
queries.push(originalQuestion);

// Palauta 3 erillistä itemiä (2 LLM:n generoitua + alkuperäinen)
return queries.map((query, index) => ({
  json: {
    query: query,
    query_index: index + 1,
    original_question: originalQuestion
  }
}));

const results = $input.all();
let originalQuestion = "unknown";
try {
  originalQuestion = $("Telegram Trigger").first().json.message?.text || 
                     results[0]?.json?.original_question || 
                     "unknown";
} catch (e) {
  originalQuestion = "unknown";
}

const uniqueMap = new Map();
results.forEach(item => {
  const key = `${item.json.document_id}_${item.json.slide_number}`;
  const existing = uniqueMap.get(key);
  if (!existing || item.json.similarity > existing.similarity) {
    uniqueMap.set(key, item.json);
  }
});

const uniqueResults = Array.from(uniqueMap.values())
  .sort((a, b) => b.similarity - a.similarity);

const documentSummaries = new Map();
uniqueResults.forEach(slide => {
  if (!documentSummaries.has(slide.document_id)) {
    documentSummaries.set(slide.document_id, {
      title: slide.document_title,
      topic: slide.document_topic,
      summary: slide.document_summary
    });
  }
});

const documentContext = Array.from(documentSummaries.values())
  .map(doc => `Document: ${doc.title}
Topic: ${doc.topic}
Summary: ${doc.summary}`).join('\n\n');

const slidesText = uniqueResults.map(slide => {
  let slideText = `Source: ${slide.document_title}, Slide ${slide.slide_number}
Relevance: ${slide.similarity.toFixed(2)}
Content: ${slide.content.replace(/\\n/g, '\n')}`;

  if (slide.image_url) {
    slideText += `\nImage: ${slide.image_url}`;
  }

  return slideText;
}).join('\n---\n');

const userMessage = `User question: ${originalQuestion}

DOCUMENT CONTEXT (use this to understand the broader topic of each presentation):
${documentContext}

RETRIEVED SLIDES (use these as your primary source):
${slidesText}

TASK: Based on the slides and document context above, provide ONE unified and actionable answer.
- Cite slides as: [document_title], Slide [slide_number]
- If a slide has an Image URL, include it in your response as a relevant visual reference
- Use document summaries to provide broader context when relevant
- Respond in the same language as the user's question`;

return [{
  json: {
    original_question: originalQuestion,
    slides: uniqueResults,
    slide_count: uniqueResults.length,
    user_message: userMessage
  }
}];
